#include <iostream>
using namespace std;
int main()
{
    int l,n,z;
    cin>>l>>n;
    int max=0,max2=0;
    int a[n],t[n],t2[n];
    for (int i=0;i<n;i++)
    {
        cin>>a[i];
        if(a[i]<l+1-a[i])
        {
            t[i]=a[i];
            t2[i]=l+1-a[i];
        }
        else
        {
            t[i]=l+1-a[i];
            t2[i]=a[i];
        }
        if (t[i]>max)
        {
            max=t[i];
        }
        if (t2[i]>max2)
        {
            max2=t2[i];
        }
    }
    cout<<max<<" "<<max2;
    return 0;
}
